const runId = $('WF09 Trigger').first().json.runId;

// Get assembled draft from event payload
let qaPayload = {};
try {
  qaPayload = JSON.parse($('Fetch Assembled Draft').first().json.payload_json || '{}');
} catch(e) {}

const sections = $('Fetch All Draft Sections').all().map(i => i.json);
const wordCount = qaPayload.wordCount || 0;
const qaReport = qaPayload.qaReport || {};

console.log(`[WF09][${runId}] Rendering HTML preview for ${sections.length} sections...`);

// Build HTML preview
const tocHtml = sections.map((s, i) => 
  `<li><a href="#section-${i}">${s.section_name}</a></li>`
).join('');

const sectionsHtml = sections.map((s, i) => {
  // Convert basic markdown to HTML
  let content = (s.content || '').replace(/^## (.+)$/gm, '<h3>$1</h3>').replace(/^### (.+)$/gm, '<h4>$1</h4>').replace(/^\*\*(.+?)\*\*$/gm, '<strong>$1</strong>').replace(/^- (.+)$/gm, '<li>$1</li>').replace(/(<li>.+<\/li>)/s, '<ul>$1</ul>').replace(/\n\n/g, '</p><p>').replace(/^([^<].+)$/gm, '<p>$1</p>');
  return `<section id="section-${i}">
    <h2>${s.section_name}</h2>
    <div class="confidence">Confidence: ${Math.round((s.confidence || 0.8) * 100)}%</div>
    <div class="content">${content}</div>
  </section>`;
}).join('\n');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>BRD - Generated by Consultant OS</title>
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; max-width: 960px; margin: 0 auto; padding: 2rem; color: #1a202c; background: #fff; }
    h1 { color: #1e3a5f; border-bottom: 3px solid #0ea5e9; padding-bottom: 0.5rem; }
    h2 { color: #1e3a5f; margin-top: 2rem; border-left: 4px solid #0ea5e9; padding-left: 1rem; }
    h3, h4 { color: #2d3748; }
    .meta { color: #64748b; font-size: 0.875rem; margin-bottom: 2rem; }
    .toc { background: #f8fafc; border: 1px solid #e2e8f0; padding: 1.5rem; border-radius: 8px; margin: 2rem 0; }
    .toc ol { margin: 0; padding-left: 1.5rem; }
    .toc a { color: #0ea5e9; text-decoration: none; }
    section { margin: 2rem 0; padding: 1.5rem; border: 1px solid #e2e8f0; border-radius: 8px; }
    .confidence { font-size: 0.75rem; color: #64748b; margin-bottom: 1rem; }
    .qa-report { background: #fffbeb; border: 1px solid #fbbf24; padding: 1rem; border-radius: 8px; margin: 2rem 0; }
    table { width: 100%; border-collapse: collapse; margin: 1rem 0; }
    th { background: #1e3a5f; color: white; padding: 0.5rem; }
    td { border: 1px solid #e2e8f0; padding: 0.5rem; }
    ul, ol { padding-left: 1.5rem; }
    p { line-height: 1.6; }
  </style>
</head>
<body>
  <h1>Business Requirements Document</h1>
  <div class="meta">
    <strong>Generated by:</strong> Consultant OS BRD Automation &nbsp;|&nbsp;
    <strong>Run ID:</strong> ${runId} &nbsp;|&nbsp;
    <strong>Date:</strong> ${new Date().toLocaleDateString('en-GB', { year: 'numeric', month: 'long', day: 'numeric' })} &nbsp;|&nbsp;
    <strong>Sections:</strong> ${sections.length} &nbsp;|&nbsp;
    <strong>Words:</strong> ~${wordCount.toLocaleString()}
  </div>
  <div class="qa-report">
    <strong>QA Score:</strong> ${Math.round((qaReport.qualityScore || 0.8) * 100)}% quality &nbsp;|&nbsp; ${Math.round((qaReport.consistencyScore || 0.85) * 100)}% consistency
    ${qaReport.summary ? `<br><em>${qaReport.summary}</em>` : ''}
  </div>
  <nav class="toc">
    <strong>Table of Contents</strong>
    <ol>${tocHtml}</ol>
  </nav>
  ${sectionsHtml}
</body>
</html>`;

return [{ json: { runId, htmlPreview: html, sectionCount: sections.length, wordCount } }];

const runId = $('WF09 Trigger').first().json.runId;
const docxResult = $input.first().json || {};

// In production, these are real signed URLs from object storage
// For now, generate placeholder paths that the frontend can reference
const baseStorageUrl = process.env.STORAGE_BASE_URL || 'https://storage.consultant-os.com';

return [{
  json: {
    runId,
    outputs: {
      htmlPreviewUrl: `${baseStorageUrl}/runs/${runId}/preview/brd_preview.html`,
      docxUrl: docxResult.docxUrl || `${baseStorageUrl}/runs/${runId}/exports/brd_document.docx`,
      pdfUrl: `${baseStorageUrl}/runs/${runId}/exports/brd_document.pdf`,
      jsonUrl: `${baseStorageUrl}/runs/${runId}/json/brd_model.json`
    },
    wordCount: $('Render HTML Preview').first().json.wordCount,
    sectionCount: $('Render HTML Preview').first().json.sectionCount
  }
}];
